class Solution {
public:
    int peopleAwareOfSecret(int n, int delay, int forget) {
        const int MOD = 1e9 + 7;
        vector<int> dp(n + 1);
        dp[1] = 1;
        int share = 0, aware = 1;
        for (int i = 2; i <= n; ++i) {
            if (i > delay) share = (share + dp[i - delay]) % MOD;
            if (i > forget) share = (share - dp[i - forget] + MOD) % MOD;
            dp[i] = share;
            aware = (aware + dp[i]) % MOD;
        }
        return aware;
    }
};
